head.script:
scwin.g_sCurrDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.KRW = "KRW";
scwin.USD = "USD";
scwin.updateFlag = 0;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "FM001", compID : "lc_borrKndCd", opt : {'range': '1,10'} },
        { grpCd : "ZZ006", compID : "lc_crcCd" },
        { grpCd : "FM002", compID : "lc_intClsCd" },
        { grpCd : "FM004", compID : "lc_grtClsCd" },
        { grpCd : "FM047", compID : "lc_intPayMthdCd" },
        { grpCd : "FM127", compID : "lc_intPayDtCalnCd" },
    ];
    $c.data.setCommonCode(codeOptions);

};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    try{
        ed_intPayYmDdCnt.setValue("365");
        ed_grtYmDdCnt.setValue("365");
        lc_intClsCd.setValue("20");
        lc_intPayDtCalnCd.setValue("01");
        scwin.f_Create();


    }catch (e) {
        console.log("onUdcCompleted  : " + e);
    }
};

//-------------------------------------------------------------------------
// 신규 : 신규입력화면으로 초기화한다.
//-------------------------------------------------------------------------
scwin.f_Create = function() { 
    try{
        $c.gus.cfDisableKey();
        $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Delete]);
        ds_borrow.removeAll(); //정보초기화
        ds_borrow.insertRow(0);
        ds_borrow.setRowPosition(0);
        lc_crcCd.setValue("KRW");//lc_crcCd.setSelectedIndex(0);//lc_crcCd.index = 0;

        ed_prmsDt.setValue(scwin.g_sCurrDate);
        ed_borrDt.setValue(scwin.g_sCurrDate);

        ed_intPayYmDdCnt.setValue("365");
        ed_grtYmDdCnt.setValue("365");
        lc_intClsCd.setValue("20");
        lc_intPayDtCalnCd.setValue("01");

        $c.gus.cfDisableObjects([ed_txt_clntNm,ed_txt_acctNm,ed_txt_acctDeptNm,ed_txt_bankAcntNo,ed_txt_grtClntNm,ed_borrRamtFcrc,ed_borrRamt,ed_borrLedgNo]);
        ed_txt_borrSlipNo.setReadOnly(true);
        $c.gus.cfEnableObjects([ed_firstRpayDt,ed_firstIntDt,ed_firstGrtDt,ed_borrSlipDt,ed_grtDt,ed_dueDt,ed_borrDt,ed_prmsDt,btn_borrClntNo,btn_acctDeptCd,btn_grtClntNo,btn_rcptBankbookNo,btn_acctCd]);
        scwin.lc_crcCd_onchange();//
    }catch (e) {
        console.log("f_Create  : " + e);
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->관리부서 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openSlipNo = function (e) {
    let sSlipNo = ed_txt_borrSlipNo.getValue();
    if(!(sSlipNo == null || sSlipNo == ""))
    $c.gus.cfShowSlipInfo(sSlipNo)
};


//-------------------------------------------------------------------------
// 차임번호(조회) 찾기
//-------------------------------------------------------------------------
scwin.btn_srchBorrLedgNo_onclick = function (e) {
    scwin.f_openPopUp('2',ed_srchBorrLedgNo,null,'F');
};
//-------------------------------------------------------------------------
// 거래처코드
//-------------------------------------------------------------------------
